import UIKit
import GoogleMaps
import StripePaymentSheet

class ViewController: UIViewController {

    private var paymentSheet: PaymentSheet?

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .white

        setupMapView()
        setupStripeButton()
    }

    private func setupMapView() {
        let camera = GMSCameraPosition.camera(withLatitude: 37.7749, longitude: -122.4194, zoom: 12.0)
        let mapView = GMSMapView.map(withFrame: CGRect.zero, camera: camera)
        mapView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(mapView)

        NSLayoutConstraint.activate([
            mapView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            mapView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            mapView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            mapView.heightAnchor.constraint(equalTo: view.heightAnchor, multiplier: 0.6)
        ])

        let marker = GMSMarker()
        marker.position = CLLocationCoordinate2D(latitude: 37.7749, longitude: -122.4194)
        marker.title = "San Francisco"
        marker.snippet = "The City by the Bay"
        marker.map = mapView
    }

    private func setupStripeButton() {
        let payButton = UIButton(type: .system)
        payButton.setTitle("Pay with Stripe", for: .normal)
        payButton.titleLabel?.font = UIFont.systemFont(ofSize: 20, weight: .bold)
        payButton.backgroundColor = .systemBlue
        payButton.setTitleColor(.white, for: .normal)
        payButton.layer.cornerRadius = 10
        payButton.addTarget(self, action: #selector(didTapPayButton), for: .touchUpInside)
        payButton.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(payButton)

        NSLayoutConstraint.activate([
            payButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            payButton.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: view.frame.height * 0.6 + 50),
            payButton.widthAnchor.constraint(equalToConstant: 250),
            payButton.heightAnchor.constraint(equalToConstant: 60)
        ])
    }

    @objc private func didTapPayButton() {
        let dummyClientSecret = "pi_1234567890abcdef1234567890abcdef_secret_INVALIDFORPRODUCTIONDEMO"

        var configuration = PaymentSheet.Configuration()
        configuration.merchantDisplayName = "Your Company Name"
        
        paymentSheet = PaymentSheet(paymentIntentClientSecret: dummyClientSecret, configuration: configuration)
        
        paymentSheet?.present(from: self) { [weak self] paymentResult in
            guard let self = self else { return }
            
            switch paymentResult {
            case .completed:
                self.showPaymentResultAlert(message: "Payment process completed (Note: This was a demo simulation and no actual transaction occurred without a backend).", success: true)
            case .canceled:
                self.showPaymentResultAlert(message: "Payment canceled.", success: false)
            case .failed(let error):
                self.showPaymentResultAlert(message: "Payment failed. This is expected without a valid client secret from a backend. Error: \(error.localizedDescription)", success: false)
            }
        }
    }
    
    private func showPaymentResultAlert(message: String, success: Bool) {
        let alert = UIAlertController(title: success ? "Success" : "Failure",
                                      message: message,
                                      preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default, handler: nil))
        present(alert, animated: true, completion: nil)
    }
}